// Format Teams message with adaptive card
const item = $json;
const scoreColor = item.combinedScore >= 90 ? '#FF0000' : '#FF6B6B'; // Red for high priority

const teamsMessage = {
  "@type": "MessageCard",
  "@context": "https://schema.org/extensions",
  "summary": item.title,
  "themeColor": scoreColor,
  "sections": [
    {
      "activityTitle": item.title,
      "activitySubtitle": `${item.source} • Score: ${item.combinedScore}/100`,
      "text": item.summary,
      "potentialAction": [
        {
          "@type": "OpenUri",
          "name": "Read Full Article",
          "targets": [{"os": "default", "uri": item.link}]
        }
      ]
    },
    {
      "activityTitle": "Intelligence Scores",
      "facts": [
        {"name": "Relevance", "value": `${item.relevanceScore}/100`},
        {"name": "Novelty", "value": `${item.noveltyScore}/100`},
        {"name": "Quality", "value": `${item.qualityScore}/100`},
        {"name": "Combined", "value": `${item.combinedScore}/100`}
      ]
    }
  ]
};

return { ...item, teamsMessage };

// Format email alert
const item = $json;

const emailBody = `
Hi Leadership,

High-priority intelligence alert (Score: ${item.combinedScore}/100)

**${item.title}**

${item.summary}

**Details:**
- Source: ${item.source}
- Published: ${new Date(item.published_date).toLocaleString()}
- Relevance: ${item.relevanceScore}/100 (AI Governance/Enterprise/Policy/PCA impact)
- Novelty: ${item.noveltyScore}/100
- Quality: ${item.qualityScore}/100

**Read more:** ${item.link}

---
This is an automated alert from the HC/PHAC Intelligence Monitoring Platform.
`;

return { ...item, emailBody };
